// ============================================================
// Collect project bootstrap inputs from the trigger form.
// In production, use a Webhook + Form or Set node with
// predefined values.
// ============================================================

return [{
  json: {
    project_name: $input.first().json.project_name || "My Novel",
    project_slug: ($input.first().json.project_name || "my-novel")
      .toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''),
    description: $input.first().json.description || "",
    genre: $input.first().json.genre || ["fantasy"],
    sub_genre: $input.first().json.sub_genre || [],
    target_audience: $input.first().json.target_audience || "18-35",
    tone: $input.first().json.tone || "热血",
    style_profile_desc: $input.first().json.style_profile_desc || "第三人称，信息密度高",
    target_total_words: $input.first().json.target_total_words || 500000,
    daily_target_words_count: $input.first().json.daily_target_words_count || 3000,
    blog_provider_val: $input.first().json.blog_provider_val || "wordpress",
    auto_publish: $input.first().json.auto_publish || false,
    quality_threshold: $input.first().json.quality_threshold || 85,
    max_revise_count: $input.first().json.max_revise_count || 2,
    trigger_bible: $input.first().json.trigger_bible || true
  }
}];

// ============================================================
// Build the bible generation prompt.
// ============================================================

const project = $("Create Project").first().json;
const input = $("Merge Input Data").first().json;

const schemaObj = {
  world_overview: "世界观概述（500-800中文字）",
  power_system: {
    name: "力量体系名称",
    description: "力量体系描述",
    rules: ["规则示例1"],
    limitations: ["限制示例1"]
  },
  main_plot_threads: [{
    title: "剧情线标题",
    description: "剧情线描述",
    thread_type: "main|sub|background"
  }],
  characters: [{
    name: "角色名",
    role: "protagonist|antagonist|supporting|minor",
    appearance: "外貌描述",
    personality: "性格描述",
    speech_style: "说话风格",
    motivation: "核心动机",
    backstory: "背景故事"
  }],
  locations: [{
    name: "地点名",
    location_type: "city|dungeon|wilderness|organization|other",
    description: "描述"
  }],
  organizations: [{
    name: "组织名",
    description: "描述",
    goals: ["目标1"]
  }],
  items: [{
    name: "道具名",
    item_type: "weapon|consumable|quest|key|other",
    description: "描述"
  }],
  style_guide: {
    narrative_perspective: "叙事视角, 如 first_person|third_person",
    positive_examples: ["好的句式示例"],
    negative_examples: ["避免的句式示例"]
  },
  canon_rules: [{
    rule_type: "hard|soft",
    rule_text: "规则内容",
    rationale: "规则理由"
  }],
  chapter_plans: [{
    sequence: 1,
    title: "章节标题",
    plot_goals: ["本章目标"],
    summary: "章节概要用中文写（一句话）",
    target_word_count: 3000,
    arc_stage: "setup|build|climax|resolution"
  }]
};

const prompt = "你是一位资深小说策划编辑。请为以下新小说项目生成完整的初始圣经。\n\n项目信息：\n- 书名：${project.name}\n- 类型：${input.genre}\n- 目标读者：${input.target_audience}\n- 文风基调：${input.tone}\n\n请严格按以下 JSON schema 输出（所有 key 必须使用英文，所有内容的 value 用中文写）：\n${JSON.stringify(schemaObj, null, 2)}\n\n输出要求：\n1. 只输出合法 JSON，不要包在代码块里\n2. world_overview 必须 500-800 中文字\n3. 至少 5-10 个角色 characters\n4. 至少 5 条 canon_rules（包含 hard 和 soft）\n5. 至少 3-5 条 main_plot_threads\n6. 前 10 章的 chapter_plans，sequence 从 1 到 10\n7. 不要包含任何解释、寒暄或 markdown";

return [{
  json: {
    project: project,
    prompt: prompt,
    system_prompt: "你是一位资深小说策划编辑。请输出严格合法的 JSON，所有字符串值必须用双引号括起来。所有 key 必须使用英文，所有内容用中文。不要输出任何解释、注释或代码块，只输出纯 JSON 对象。",
    schema: schemaObj
  }
}];

const response = $input.first().json;
let rawText = "";

if (response.message && response.message.content) {
  rawText = response.message.content;
} else if (response.choices && response.choices[0] && response.choices[0].message) {
  rawText = response.choices[0].message.content;
} else if (typeof response === "string") {
  rawText = response;
} else {
  rawText = JSON.stringify(response);
}

rawText = rawText.trim();
if (rawText.startsWith("```")) {
  var nl = rawText.indexOf("\n");
  if (nl >= 0) rawText = rawText.substring(nl + 1);
}
if (rawText.endsWith("```")) {
  rawText = rawText.substring(0, rawText.length - 3).trim();
}

function repairJSON(text) {
  var out = "";
  var i = 0;
  while (i < text.length) {
    out += text[i];
    if (text[i] === ":" && i + 1 < text.length) {
      var j = i + 1;
      while (j < text.length && (text[j] === " " || text[j] === "\n" || text[j] === "\r" || text[j] === "\t")) j++;
      if (j < text.length) {
        var ch = text[j];
        var isQuoted = (ch === '"');
        var isBracket = (ch === "[" || ch === "{");
        var isNum = (ch >= "0" && ch <= "9") || ch === "-";
        var tok4 = text.substring(j, j + 4);
        var tok5 = text.substring(j, j + 5);
        var isKeyword = (tok4 === "true" || tok5 === "false" || tok4 === "null");
        if (!isQuoted && !isBracket && !isNum && !isKeyword) {
          var k = j;
          while (k < text.length && text[k] !== "," && text[k] !== "\n" && text[k] !== "}" && text[k] !== "]") k++;
          var val = text.substring(j, k).trim();
          var escaped = val.replace(/"/g, '\\"').replace(/\\/g, '\\\\');
          out += '"' + val + '"';
          i = k - 1;
        } else {
          i = j - 1;
        }
      }
    }
    i++;
  }
  return out;
}

// Remove trailing commas
rawText = rawText.replace(/,(s*[}\]])/g, "$1");

let bible;
try {
  bible = JSON.parse(rawText);
} catch (e1) {
  try {
    var repaired = repairJSON(rawText);
    repaired = repaired.replace(/,(s*[}\]])/g, "$1");
    bible = JSON.parse(repaired);
  } catch (e2) {
    throw new Error(
      "JSON failed after repair. " +
      "Err: " + e1.message + " | " +
      "Repair err: " + e2.message
    );
  }
}

if (!bible.world_overview || !bible.characters || !bible.main_plot_threads) {
  throw new Error("Missing fields: " + Object.keys(bible).join(", "));
}

return [{ json: { project: $("Create Project").first().json, bible: bible } }];

const data = $input.first().json;
const project = data.project;
const bible = data.bible;
const items = [];

// style_guides
if (bible.style_guide) {
  items.push({ json: {
    table: 'style_guides',
    values: [project.id, '\u521d\u59cb\u98ce\u683c\u6307\u5357', bible.style_guide.narrative_perspective || '', JSON.stringify(bible.style_guide.positive_examples || []), JSON.stringify(bible.style_guide.negative_examples || [])],
    sql: 'INSERT INTO style_guides (project_id, name, style_text, positive_examples, negative_examples) VALUES ($1, $2, $3, $4, $5) RETURNING id'
  }});
}

// characters - matching actual schema (name, aliases, role, personality, motivation, speech_style, appearance, backstory)
(bible.characters || []).forEach(function(c) {
  items.push({ json: {
    table: 'characters',
    values: [project.id, c.name, c.role || '', c.personality || '', c.motivation || '', c.speech_style || '', c.appearance || '', c.backstory || ''],
    sql: 'INSERT INTO characters (project_id, name, role, personality, motivation, speech_style, appearance, backstory) VALUES ($1, $2, $3, $4, $5, $6, $7, $8) RETURNING id'
  }});
});

// locations
(bible.locations || []).forEach(function(l) {
  items.push({ json: {
    table: 'locations',
    values: [project.id, l.name, l.location_type || '', l.description || ''],
    sql: 'INSERT INTO locations (project_id, name, type, description) VALUES ($1, $2, $3, $4) RETURNING id'
  }});
});

// organizations
(bible.organizations || []).forEach(function(o) {
  items.push({ json: {
    table: 'organizations',
    values: [project.id, o.name, o.description || '', JSON.stringify(o.goals || [])],
    sql: 'INSERT INTO organizations (project_id, name, description, goals) VALUES ($1, $2, $3, $4) RETURNING id'
  }});
});

// items
(bible.items || []).forEach(function(it) {
  items.push({ json: {
    table: 'items',
    values: [project.id, it.name, it.item_type || '', it.description || ''],
    sql: 'INSERT INTO items (project_id, name, item_type, description) VALUES ($1, $2, $3, $4) RETURNING id'
  }});
});

// world_lore
if (bible.world_overview) {
  items.push({ json: {
    table: 'world_lore',
    values: [project.id, '\u4e16\u754c\u89c2\u6982\u8ff0', 'world_overview', bible.world_overview],
    sql: 'INSERT INTO world_lore (project_id, title, lore_type, content) VALUES ($1, $2, $3, $4) RETURNING id'
  }});
}

// magic_or_power_systems
if (bible.power_system) {
  items.push({ json: {
    table: 'magic_or_power_systems',
    values: [project.id, bible.power_system.name || '\u529b\u91cf\u4f53\u7cfb', bible.power_system.description || '', JSON.stringify(bible.power_system.rules || []), JSON.stringify(bible.power_system.limitations || [])],
    sql: 'INSERT INTO magic_or_power_systems (project_id, name, description, rules, limitations) VALUES ($1, $2, $3, $4, $5) RETURNING id'
  }});
}

// canon_rules - FIXED: removed rationale, reorder (rule_type, rule_text, severity)
(bible.canon_rules || []).forEach(function(r) {
  items.push({ json: {
    table: 'canon_rules',
    values: [project.id, r.rule_type || 'hard', r.rule_text || '', r.rule_type === 'soft' ? 'soft' : 'hard'],
    sql: 'INSERT INTO canon_rules (project_id, rule_type, rule_text, severity) VALUES ($1, $2, $3, $4) RETURNING id'
  }});
});

// plot_threads - FIXED: match actual schema (name, description)
(bible.main_plot_threads || []).forEach(function(pt) {
  items.push({ json: {
    table: 'plot_threads',
    values: [project.id, pt.title || '', pt.description || '', pt.thread_type === 'main' ? 1 : pt.thread_type === 'sub' ? 2 : 3],
    sql: 'INSERT INTO plot_threads (project_id, name, description, priority) VALUES ($1, $2, $3, $4) RETURNING id'
  }});
});

// chapter_plans - FIXED: match actual schema (outline instead of summary, no arc_stage)
(bible.chapter_plans || []).forEach(function(cp) {
  items.push({ json: {
    table: 'chapter_plans',
    values: [project.id, cp.sequence, cp.title || '', JSON.stringify(cp.plot_goals || []), cp.summary || '', cp.target_word_count || 3000],
    sql: 'INSERT INTO chapter_plans (project_id, sequence, title, plot_goals, outline, target_word_count) VALUES ($1, $2, $3, $4, $5, $6) RETURNING id'
  }});
});

return items;

// Process ALL items from Split Bible to DB Rows
const items = $input.all();

function esc(val) {
  if (val === undefined || val === null) return "NULL";
  if (typeof val === "boolean") return val ? "TRUE" : "FALSE";
  if (typeof val === "number") return String(val);
  var str = typeof val === "object" ? JSON.stringify(val) : String(val);
  return "'" + str.replace(/'/g, "''") + "'";
}

return items.map(function(item) {
  var j = item.json;
  var vals = j.values || [];
  var sql = j.sql || "";

  for (var i = 0; i < vals.length; i++) {
    sql = sql.replace("$" + (i + 1), esc(vals[i]));
  }

  return { json: { table: j.table, sql: sql } };
});

// Get bible data from Parse Bible Response
const bibleData = $("Parse Bible Response").first().json;
const bible = bibleData.bible;
const project = bibleData.project;
const vectors = [];

// Characters
(bible.characters || []).forEach(function(c) {
  vectors.push({
    json: {
      project_id: project.id,
      source_type: "character_profile",
      title: c.name,
      content: JSON.stringify({name: c.name, role: c.role, personality: c.personality, speech_style: c.speech_style, motivation: c.motivation, backstory: c.backstory}),
      input_text: c.name + " - " + (c.role || "") + " - " + (c.personality || "")
    }
  });
});

// World overview
if (bible.world_overview) {
  vectors.push({
    json: {
      project_id: project.id,
      source_type: "world_lore",
      title: "World Overview",
      content: bible.world_overview,
      input_text: bible.world_overview
    }
  });
}

// Power system
if (bible.power_system) {
  vectors.push({
    json: {
      project_id: project.id,
      source_type: "world_lore",
      title: "Power System: " + (bible.power_system.name || ""),
      content: JSON.stringify(bible.power_system),
      input_text: (bible.power_system.name || "") + " - " + (bible.power_system.description || "")
    }
  });
}

// Locations
(bible.locations || []).forEach(function(l) {
  vectors.push({
    json: {
      project_id: project.id,
      source_type: "world_lore",
      title: "Location: " + l.name,
      content: JSON.stringify(l),
      input_text: l.name + " - " + (l.description || "")
    }
  });
});

// Organizations
(bible.organizations || []).forEach(function(o) {
  vectors.push({
    json: {
      project_id: project.id,
      source_type: "world_lore",
      title: "Organization: " + o.name,
      content: JSON.stringify(o),
      input_text: o.name + " - " + (o.description || "")
    }
  });
});

return vectors;

// Generate placeholder embedding vector + inline SQL for insert
const items = $input.all();

function esc(val) {
  if (val === undefined || val === null) return "NULL";
  if (typeof val === "boolean") return val ? "TRUE" : "FALSE";
  if (typeof val === "number") return String(val);
  var str = typeof val === "object" ? JSON.stringify(val) : String(val);
  return "'" + str.replace(/'/g, "''") + "'";
}

return items.map(function(item) {
  var d = item.json;
  var vec = new Array(1536).fill(0);
  var vecStr = "'[" + vec.join(",") + "]'";
  var sql = "INSERT INTO vector_documents (project_id, source_type, title, content, embedding) VALUES ("
    + esc(d.project_id) + ", "
    + esc(d.source_type) + ", "
    + esc(d.title) + ", "
    + esc(d.content) + ", "
    + vecStr + "::vector"
  + ") ON CONFLICT DO NOTHING RETURNING id;";
  return { json: { sql: sql, embedding: vec } };
});

const project = $('Create Project').first().json;
const items = $input.all();

return [{
  json: {
    project_id: project.id,
    project_name: project.name,
    status: 'bootstrap_complete',
    message: 'Project "' + project.name + '" (ID: ' + project.id + ') bootstrapped. Set status to active, then run Weekly Arc Planner.',
    entities_created: items.length
  }
}];

// Build INSERT SQL with proper PostgreSQL single-quote escaping
const input = $("Prepare Project Input").first().json;

function esc(val) {
  if (val === undefined || val === null) return "NULL";
  if (typeof val === "boolean") return val ? "TRUE" : "FALSE";
  if (typeof val === "number") return String(val);
  const str = typeof val === "object" ? JSON.stringify(val) : String(val);
  // PostgreSQL: single quotes, doubling any embedded single quotes
  return "'" + str.replace(/'/g, "''") + "'";
}

const name = esc(input.project_name);
const genre = esc(input.genre ? input.genre.join(", ") : "fantasy");
const audience = esc(input.target_audience);
const style = esc(JSON.stringify({
  tone: input.tone || "热血",
  narrative_style: input.style_profile_desc || "",
  forbidden_phrases: ["眼中闪过","嘴角上扬","不由得"],
  preferred_techniques: ["动作链","对话推进","感官细节"]
}));
const totalWords = esc(input.target_total_words || 500000);
const dailyWords = esc(input.daily_target_words_count || 3000);
const blog = esc(input.blog_provider_val || "wordpress");
const autoPub = esc(input.auto_publish || false);
const qThreshold = esc(input.quality_threshold || 85);
const meta = esc(JSON.stringify({
  synopsis: input.description || "",
  sub_genre: input.sub_genre || [],
  slug: input.project_slug || "",
  max_revise_count: input.max_revise_count || 2
}));

const sql = "INSERT INTO projects (name, genre, target_audience, style_profile, total_target_words, daily_target_words, blog_provider, auto_publish, quality_threshold, status, metadata) VALUES (" + name + ", " + genre + ", " + audience + ", " + style + ", " + totalWords + ", " + dailyWords + ", " + blog + ", " + autoPub + ", " + qThreshold + ", " + esc("draft") + ", " + meta + ") RETURNING id, name, status, created_at;";

return [{ json: { ...input, schema_ready: $json.schema_ready, _sql: sql } }];
